/**
 * Chapter Fields Configuration - Single Source of Truth
 *
 * Centralized configuration for all 11 IDEA framework chapters including:
 * - Chapter metadata (titles, descriptions)
 * - Associated brand data fields
 * - Field types and validation
 * - Field source tracking (AI vs manual)
 *
 * This ensures consistent field mapping across:
 * - ChapterSectionAccordion component
 * - Brand form panels
 * - Data persistence layer
 * - AI coach interactions
 */

/**
 * Field source indicator
 * - 'ai': Generated by AI assistant
 * - 'manual': Manually entered by user
 */
export type FieldSource = 'ai' | 'manual';

/**
 * Chapter completion status
 * - 'completed': Chapter has been finished
 * - 'active': Currently working on this chapter
 * - 'future': Not yet started, locked until previous chapters complete
 */
export type ChapterStatus = 'completed' | 'active' | 'future';

/**
 * Field type determines UI component
 * - 'text': Single-line input
 * - 'textarea': Multi-line textarea
 * - 'array': Array of strings (for lists)
 */
export type FieldType = 'text' | 'textarea' | 'array';

/**
 * Individual field configuration within a chapter
 */
export interface ChapterField {
  /** Unique field identifier (maps to BrandData keys) */
  id: string;

  /** Display label for the field */
  label: string;

  /** Field type (determines UI component) */
  type: FieldType;

  /** Placeholder text for empty fields */
  placeholder: string;

  /** Is this field required to complete the chapter? */
  required: boolean;

  /** Help text or description */
  helpText?: string;
}

/**
 * Chapter configuration
 */
export interface Chapter {
  /** Unique chapter identifier */
  id: string;

  /** Display title */
  title: string;

  /** Short description of chapter purpose */
  description: string;

  /** IDEA framework pillar this chapter belongs to */
  pillar: 'insight' | 'distinctive' | 'empathy' | 'authentic' | 'foundation';

  /** Fields included in this chapter */
  fields: ChapterField[];

  /** Order in the journey (1-11) */
  order: number;
}

