/**
 * Maps book chapter number (1–11) to the CHAPTER_FIELDS_MAP key.
 * Single source of truth — replaces inline copies in BrandCoachV2.tsx.
 */
export const BOOK_CHAPTER_NUMBER_TO_FIELDS_KEY: Record<number, string> = {
  1: 'BRAND_FOUNDATION',  2: 'BRAND_VALUES',        3: 'CUSTOMER_AVATAR',
  4: 'MARKET_INSIGHT',    5: 'BUYER_INTENT',         6: 'POSITIONING',
  7: 'BRAND_PERSONALITY', 8: 'EMOTIONAL_CONNECTION', 9: 'CUSTOMER_EXPERIENCE',
  10: 'BRAND_AUTHORITY',  11: 'BRAND_AUTHENTICITY',
};

/**
 * Get chapters in order
 */
export function getChaptersInOrder(): Chapter[] {
  return Object.values(CHAPTER_FIELDS_MAP).sort((a, b) => a.order - b.order);
}

/**
 * Get chapter by ID
 */
export function getChapterById(id: string): Chapter | undefined {
  return CHAPTER_FIELDS_MAP[id.toUpperCase().replace(/-/g, '_')];
}

/**
 * Get chapters by pillar
 */
export function getChaptersByPillar(pillar: Chapter['pillar']): Chapter[] {
  return Object.values(CHAPTER_FIELDS_MAP)
    .filter(chapter => chapter.pillar === pillar)
    .sort((a, b) => a.order - b.order);
}

/**
 * Get total field count across all chapters
 */
export function getTotalFieldCount(): number {
  return Object.values(CHAPTER_FIELDS_MAP).reduce(
    (total, chapter) => total + chapter.fields.length,
    0
  );
}

/**
 * Get required field count for a chapter
 */
export function getRequiredFieldCount(chapterId: string): number {
  const chapter = getChapterById(chapterId);
  if (!chapter) return 0;
  return chapter.fields.filter(field => field.required).length;
}
